hdl_code.vhdl:
-- FPGA Blinking LED
entity blink is port(clk: in bit; led: out bit); end blink;
architecture rtl of blink is signal cnt: integer; begin
process(clk) begin if clk'event and clk='1' then cnt <= cnt + 1; led <= cnt(24); end if; end process; end rtl;

hdl_code.verilog:
module blink(input clk, output led);
  reg [24:0] cnt;
  always @(posedge clk) cnt <= cnt + 1;
  assign led = cnt[24];
endmodule

